def solve(*args):
    if len(args) != 2:
        raise ValueError("Two arguments are required.")

    try:
        a = float(args[0])
        b = float(args[1])
    except ValueError:
        raise ValueError("Both arguments must be numbers.")

    if b == 0:
        raise ZeroDivisionError("Division by zero is not allowed.")

    return a / b
